import React from 'react'

export const Header = () => {
  return (
    <div className="breadcrumb-wrapper md:h-[50vh] flex justify-center items-center flex-col bg-[#C19EE0]">
      <h1 className='text-black font-bold'>Why techfighters</h1>
      <p className='w-[70vw] text-black'>
        At <span className='bg-[#A06CD5] text-black p-1'>techfighters</span> we are dedicated to empowering students with the skills and knowledge needed to succeed in their careers. Our courses are designed with industry experts to provide practical and up-to-date learning experiences. Whether you're looking to enhance your skills, switch careers, or boost your career prospects, techfighters is here to guide you every step of the way.
      </p>
    </div>
  )
}
